SourceCode.Declaration:
[DataContract]
public final class PurchInvoiceBusinessEventContract extends BusinessEventsContract
{
    private VendInvoiceId       invoiceId;
    private TransDate           transactionDate;
    private PurchId             purchId;
    private str                 purchAgreementNumber;
    private str                 dealNumber;
    private str                 source;
    private VendAccount         vendorNo;
    private AmountCur           invoiceAmount;
    private CurrencyCode        currency;
    private RefRecId            recordId;
    private str                 transactionType;

    // Lines collection
    private List                lines;

}

Method.Source:
protected void initialize(VendInvoiceJour _journal)
{
    PurchTable              purchTable;
    PurchAgreementHeader    purchAgreementHeader;
    AgreementHeaderDefault  agreementHeaderDefault;

    // Hardcoded values
    transactionType = 'PurchaseInvoice';
    source          = 'D365';

    // Populate standard header fields from journal
    invoiceId       = _journal.InvoiceId;
    transactionDate = _journal.InvoiceDate;
    purchId         = _journal.PurchId;
    vendorNo        = _journal.OrderAccount; // or InvoiceAccount, depending on your requirement
    currency        = _journal.CurrencyCode;
    recordId        = _journal.RecId;

    // Lookup Purchase Agreement and Deal Number
    purchTable = PurchTable::find(_journal.PurchId);

    select firstonly purchAgreementHeader
        where purchAgreementHeader.RecId == purchTable.MatchingAgreement;

    if (purchAgreementHeader.RecId)
    {
        purchAgreementNumber = purchAgreementHeader.PurchNumberSequence;

        select firstonly agreementHeaderDefault
            where agreementHeaderDefault.AgreementHeader == purchAgreementHeader.RecId;

        if (agreementHeaderDefault.RecId)
        {
            dealNumber = agreementHeaderDefault.ETGDealNumber;
        }
    }

    // Initialize lines list
    lines = new List(Types::Class);

    // Populate lines and calculate total invoice amount
    this.populateLines(_journal);
}

private void populateLines(VendInvoiceJour _journal)
{
    VendInvoiceTrans invoiceTrans;

    invoiceAmount = 0;

    // Loop through lines for this specific invoice
    while select invoiceTrans
        where invoiceTrans.InvoiceId == _journal.InvoiceId
           && invoiceTrans.InvoiceDate == _journal.InvoiceDate
           && invoiceTrans.PurchId == _journal.PurchId
    {
        // Accumulate total header amount
        invoiceAmount += invoiceTrans.LineAmount;

        // Instantiate the line contract and pass down line values
        PurchInvoiceLineBusinessEventContract lineContract = PurchInvoiceLineBusinessEventContract::construct(
            _journal.InvoiceId,
            invoiceTrans.Qty,
            invoiceTrans.LineAmount,
            invoiceTrans.ItemId,
            _journal.CurrencyCode,
            invoiceTrans.TaxGroup, // Alternatively invoiceTrans.TaxItemGroup
            invoiceTrans.TaxAmount);

        lines.addEnd(lineContract);
    }
}

public static PurchInvoiceBusinessEventContract newFromVendInvoiceJour(VendInvoiceJour _journal)
{
    var contract = new PurchInvoiceBusinessEventContract();
    contract.initialize(_journal);
    return contract;
}

// --- Data Members for Collections ---

[DataMember('Lines'),
 DataCollectionAttribute(Types::Class, classStr(PurchInvoiceLineBusinessEventContract)),
 BusinessEventsDataMember('Invoice Lines')]
public List parmLines(List _lines = lines)
{
    lines = _lines;
    return lines;
}

